import{_ as p,o as t,c as o,ag as s}from"./chunks/framework.DtEl18Xn.js";const a="/getbiji-docs-v3/images/QHofb2B0po5eFwxV3jccsPeZnkc.png",r="/getbiji-docs-v3/images/KD5zb6DfYoit77xs2bLcXD37nAg.png",e="/getbiji-docs-v3/images/D3SYbrjKBohUChxiiv9c6C8znGd.png",l="/getbiji-docs-v3/images/Q51RbOJRIoWBKTxDrVecld1inWf.png",n="/getbiji-docs-v3/images/VwGnbLgxroJr8qxNOZUcY06Mnsd.png",c="/getbiji-docs-v3/images/MfT2bK30XoTJzrx2HtRcWmKpnGh.png",g="/getbiji-docs-v3/images/B6ahbzjuZokVrmxE78ScLpKHnVe.png",m="/getbiji-docs-v3/images/P987bN9gvosMABxmpoKcT0fincg.png",d="/getbiji-docs-v3/images/HEUTbVF7noJCbOxwh7NcBBOEnXb.png",b="/getbiji-docs-v3/images/Y5ddb4dreoHRy7xHLxicpyQ5nrf.png",_="/getbiji-docs-v3/images/UQkSb5GKloob3Cxe2HKc0EmSnld.png",h="/getbiji-docs-v3/images/FGmpbMg08o2EBvxSVsfc69cGnNe.png",x="/getbiji-docs-v3/images/KsQdbmbcGo2kNAxRq7WctJuZnfI.png",u="/getbiji-docs-v3/images/E4vvbxxc2oWXzix0YjQcxXjhnyd.png",f="/getbiji-docs-v3/images/Z2RHbgy8Cof9dTxVHH5cdJIFned.png",v="/getbiji-docs-v3/images/Lj1ub7ugeoMpXAxB0N5ctQwYnSh.png",j="/getbiji-docs-v3/images/QrM3bb1E7oZyEMxsFzFcm4pHnTh.png",q="/getbiji-docs-v3/images/Y5OpbZny5opHxrxArMRcXRrdnwg.png",P="/getbiji-docs-v3/images/Rl3CbILKDoCYgYxb5rgcnJzhnbw.png",k="/getbiji-docs-v3/images/YEkebRi8xoCSHSx12Y9cFnJqnHc.png",T="/getbiji-docs-v3/images/YsAWb8XVOoSHALxfwLncVCOfnTe.png",E="/getbiji-docs-v3/images/ZyO9bMXn9os3taxaU9PcEuO5nRh.png",H="/getbiji-docs-v3/images/OpyVb6LKqoDos8xQOiycR6P0nfe.png",V="/getbiji-docs-v3/images/Y0PYbEQYtohVg7xTMQJc1k19nEe.png",Y="/getbiji-docs-v3/images/Pb3Db8L16oEhRnxkOwDcQWn0nQf.png",D=JSON.parse('{"title":"分享和团队管理","description":"","frontmatter":{"title":"分享和团队管理","category":"Get笔记知识库","lastUpdated":"2026-03-14T14:58:02.765Z"},"headers":[],"relativePath":"get笔记知识库/分享和团队管理.md","filePath":"get笔记知识库/分享和团队管理.md"}'),R={name:"get笔记知识库/分享和团队管理.md"};function S(A,i,O,Q,K,B){return t(),o("div",null,[...i[0]||(i[0]=[s('<h1 id="分享和团队管理" tabindex="-1">分享和团队管理 <a class="header-anchor" href="#分享和团队管理" aria-label="Permalink to &quot;分享和团队管理&quot;">​</a></h1><p>📤 <strong>分享订阅，知识触手可及</strong></p><p>支持将知识库以多种形式（微信小程序、分享海报、链接等）分享给他人，也可订阅其他人的「靠谱知识库」，获取独家内容和实时更新。共享智慧，扩展视野，让学习更高效！</p><p>同时，新增了知识库的<strong>团队管理功能</strong>，可以让知识库在限定范围内进行共创和使用，大大提高了知识库的共创和灵活性。</p><h1 id="app端-使用说明" tabindex="-1">APP端-使用说明 <a class="header-anchor" href="#app端-使用说明" aria-label="Permalink to &quot;APP端-使用说明&quot;">​</a></h1><p>个人自己创建的知识库，<strong>默认是私密状态，仅自己可见。</strong></p><p>如果想要分享给他人查看，或邀请团队成员共同使用，需要手动设置知识库的分享权限。</p><p><strong>权限包括：</strong></p><ul><li><strong>公开</strong>，则获得你的知识库分享链接 or 分享海报的人，都可以访问知识库使用（AI搜索、查看内容）</li><li><strong>团队</strong>，则获得你的知识库分享链接 or 分享海报的人，无法直接访问知识库内容，需要先申请加入才能使用</li><li>创建人可以自定义成员加入时，是否需要管理员审核通过后才能加入</li></ul><h2 id="分享自己的知识库" tabindex="-1">分享自己的知识库 <a class="header-anchor" href="#分享自己的知识库" aria-label="Permalink to &quot;分享自己的知识库&quot;">​</a></h2><ol><li>在知识库内，点击右上角分享按钮</li><li>选择“公开”，然后将知识库通过「微信好友」、「朋友圈」、「分享海报」和「分享链接」等形式分享出去</li><li>他人在访问你的知识库时，可以直接进入知识库来使用 <img src="'+a+'" alt=""></li></ol><p><img src="'+r+'" alt=""></p><p><img src="'+e+'" alt=""></p><p><img src="'+l+'" alt=""></p><p><img src="'+n+'" alt=""></p><h2 id="订阅他人公开的知识库" tabindex="-1">订阅他人公开的知识库 <a class="header-anchor" href="#订阅他人公开的知识库" aria-label="Permalink to &quot;订阅他人公开的知识库&quot;">​</a></h2><ol><li>点击他人分享给你的知识库小程序、海报或链接</li><li>点击进入知识库页面，可以点击“+订阅”，订阅后的知识库，会出现在「我的」知识库列表内</li><li>同时，你也可以在精选 tab 下，点开官方精选知识库，并点击“订阅”按钮，完成订阅</li><li>如果想取消已订阅的知识库，可以再次点击即可“取消订阅” <img src="'+c+'" alt=""></li></ol><p><img src="'+g+'" alt=""></p><p><img src="'+m+'" alt=""></p><p><img src="'+d+'" alt=""></p><h2 id="设置团队知识库" tabindex="-1">设置团队知识库 <a class="header-anchor" href="#设置团队知识库" aria-label="Permalink to &quot;设置团队知识库&quot;">​</a></h2><ol><li>在知识库内，点击右上角分享按钮</li><li>选择“团队可见”，然后将知识库通过「微信好友」、「朋友圈」、「分享海报」和「分享链接」等形式分享出去</li><li><strong>默认“成员自动加入”是关闭的，即加入的成员需要管理员审核通过才能访问知识库</strong></li><li>其他成员点击进入知识库页面，可以点击“申请加入知识库”，然后等待知识库管理员的审核即可</li><li>管理员审核同意后，加入后的知识库，会出现在其他成员「我的」知识库列表内</li><li><strong>如果关闭打开，则不需要任何审核确认</strong>，成员可以直接加入并使用知识库</li></ol><p><img src="'+b+'" alt=""></p><p><img src="'+_+'" alt=""></p><p><img src="'+h+'" alt=""></p><p><img src="'+x+'" alt=""></p><h3 id="审核加入团队知识库申请" tabindex="-1">审核加入团队知识库申请 <a class="header-anchor" href="#审核加入团队知识库申请" aria-label="Permalink to &quot;审核加入团队知识库申请&quot;">​</a></h3><ol><li>有新的成员申请加入时，知识库顶部成员入口会有红点提醒，点击“成员”入口进入成员管理页面</li><li>可以对申请的成员进行审核，可以同意加入，也可以拒绝，同意加入则进入成员列表，可以分配具体角色权限</li><li>可以将其设置为普通成员和管理员，具体请参考下面的【角色权限说明】表格</li><li>同时，可以将已加入的成员，从知识库移除，则其无法再正常访问和使用知识库 <img src="'+u+'" alt=""></li></ol><p><img src="'+f+'" alt=""></p><p><img src="'+v+'" alt=""></p><p><img src="'+j+'" alt=""></p><h3 id="团队角色和权限说明" tabindex="-1">团队角色和权限说明 <a class="header-anchor" href="#团队角色和权限说明" aria-label="Permalink to &quot;团队角色和权限说明&quot;">​</a></h3><p>权限/角色</p><p><strong>成员</strong></p><p><strong>管理员</strong></p><p><strong>创建人</strong></p><p><strong>知识库管理权限</strong></p><p>编辑知识库名称和描述</p><p>❌</p><p>✅</p><p>✅</p><p>删除知识库</p><p>❌</p><p>❌</p><p>✅</p><p>修改分享权限</p><p>❌</p><p>❌</p><p>✅</p><p>审批成员</p><p>❌</p><p>✅</p><p>✅</p><p><strong>内容管理权限（文件/文件夹/笔记/订阅）</strong></p><p>添加</p><p>❌</p><p>✅</p><p>✅</p><p>编辑</p><p>仅可编辑自己的内容</p><p>仅可编辑自己的内容</p><p>仅可编辑自己的内容</p><p>删除</p><p>仅可删除自己的内容</p><p>仅可删除自己的内容</p><p>仅可删除自己的内容</p><p>移出</p><p>❌</p><p>可移出所有内容</p><p>可移出所有内容</p><p>追加</p><p>仅可追加自己的内容</p><p>仅可追加自己的内容</p><p>仅可追加自己的内容</p><p>订阅/取消订阅（直播/博主）</p><p>❌</p><p>✅</p><p>✅</p><p>查看、分享、复制</p><p>✅</p><p>✅</p><p>✅</p><h1 id="网页端-使用说明" tabindex="-1">网页端-使用说明 <a class="header-anchor" href="#网页端-使用说明" aria-label="Permalink to &quot;网页端-使用说明&quot;">​</a></h1><h2 id="分享自己的知识库-1" tabindex="-1">分享自己的知识库 <a class="header-anchor" href="#分享自己的知识库-1" aria-label="Permalink to &quot;分享自己的知识库&quot;">​</a></h2><ol><li>进入知识库内，点击右上角“分享”按钮，选择“公开”后，然后复制链接给他人，即可实现分享</li><li>如果不想其他人能访问到此知识库，则关闭此开关，则他人无法继续访问和使用你的知识库</li><li>如果想要团队共同维护一个知识库，则选择“团队”，即可由团队管理员共同维护此知识库 <img src="'+q+'" alt=""></li></ol><h2 id="订阅他人的知识库" tabindex="-1">订阅他人的知识库 <a class="header-anchor" href="#订阅他人的知识库" aria-label="Permalink to &quot;订阅他人的知识库&quot;">​</a></h2><ol><li><p>打开别人分享给你的知识库，点击右上角“订阅知识库”</p></li><li><p>订阅成功后，该知识库会出现在你的知识库列表内 <img src="'+P+'" alt=""></p></li><li><p>如果想取消已订阅的知识库，可以点击他人知识库的 ... 更多入口，选择“取消订阅” <img src="'+k+'" alt=""></p></li></ol><h1 id="小程序端-使用说明" tabindex="-1">小程序端-使用说明 <a class="header-anchor" href="#小程序端-使用说明" aria-label="Permalink to &quot;小程序端-使用说明&quot;">​</a></h1><ol><li>进入Get笔记小程序，点击右上角更多，可以进入知识库列表页</li><li>选择要访问的知识库，然后在知识库内，点击右上角分享按钮</li><li>选择“公开”，可以将知识库通过「微信好友」、「朋友圈」、「分享海报」和「分享链接」等形式分享出去</li><li>则他人在访问你的知识库时，可以直接进入知识库来订阅、使用</li><li>如果想要团队共同维护一个知识库，则选择“团队”，即可由团队管理员共同维护此知识库 <img src="'+T+'" alt=""></li></ol><p><img src="'+E+'" alt=""></p><p><img src="'+H+'" alt=""></p><p><img src="'+V+'" alt=""></p><p><img src="'+Y+'" alt=""></p>',93)])])}const y=p(R,[["render",S]]);export{D as __pageData,y as default};
